contracts/AuditLog.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "./interfaces/IBlockERP.sol";
import "./BlockERPCore.sol";

/**
 * @title AuditLog
 * @author BlockERP Team
 * @notice Immutable audit logging system with blockchain verification
 * @dev All system actions are recorded on-chain for compliance and transparency
 */
contract AuditLog is IAuditTypes {
    // ============ State Variables ============

    /// @notice Reference to core contract
    BlockERPCore public immutable core;

    /// @notice Audit entry counter
    uint256 private _entryIdCounter;

    /// @notice Mapping of entry ID to AuditEntry
    mapping(uint256 => AuditEntry) private _entries;

    /// @notice Array of all entry IDs
    uint256[] private _allEntryIds;

    /// @notice Mapping of user address to their entry IDs
    mapping(address => uint256[]) private _userEntries;

    /// @notice Mapping of entity type to entry IDs
    mapping(string => uint256[]) private _entityTypeEntries;

    /// @notice Mapping of entity ID to entry IDs
    mapping(uint256 => uint256[]) private _entityEntries;

    /// @notice Mapping of data hash to entry ID (for verification)
    mapping(bytes32 => uint256) private _hashToEntry;

    /// @notice Registered modules that can write to audit log
    mapping(address => bool) public authorizedModules;

    /// @notice Daily entry limits per user (0 = unlimited)
    uint256 public dailyLimitPerUser;

    /// @notice Tracking daily entries per user
    mapping(address => mapping(uint256 => uint256)) private _dailyEntryCount;

    // ============ Events ============

    event AuditEntryCreated(
        uint256 indexed entryId,
        address indexed user,
        AuditAction action,
        string entityType,
        uint256 indexed entityId,
        bytes32 dataHash
    );

    event ModuleAuthorized(
        address indexed module,
        address indexed authorizedBy
    );
    event ModuleDeauthorized(
        address indexed module,
        address indexed deauthorizedBy
    );
    event DailyLimitUpdated(uint256 previousLimit, uint256 newLimit);

    event HashVerified(
        uint256 indexed entryId,
        bytes32 dataHash,
        bool isValid,
        address verifiedBy
    );

    // ============ Modifiers ============

    modifier onlyAdmin() {
        require(
            core.hasRole(msg.sender, IAccessControl.Role.ADMIN),
            "AuditLog: caller is not admin"
        );
        _;
    }

    modifier onlyAuthorized() {
        require(
            core.hasRole(msg.sender, IAccessControl.Role.MANAGER) ||
                authorizedModules[msg.sender],
            "AuditLog: not authorized"
        );
        _;
    }

    modifier withinDailyLimit() {
        if (dailyLimitPerUser > 0) {
            uint256 today = block.timestamp / 1 days;
            require(
                _dailyEntryCount[msg.sender][today] < dailyLimitPerUser,
                "AuditLog: daily limit exceeded"
            );
            _;
            _dailyEntryCount[msg.sender][today]++;
        } else {
            _;
        }
    }

    modifier entryExists(uint256 entryId) {
        require(_entries[entryId].id != 0, "AuditLog: entry does not exist");
        _;
    }

    // ============ Constructor ============

    constructor(address _coreAddress) {
        require(_coreAddress != address(0), "AuditLog: invalid core address");
        core = BlockERPCore(_coreAddress);
        _entryIdCounter = 0;
        dailyLimitPerUser = 0; // Unlimited by default
    }

    // ============ Audit Functions ============

    /**
     * @notice Log an audit entry
     * @param user Address of the user performing the action
     * @param userName Human-readable username
     * @param action The action type
     * @param entityType Type of entity (Order, Invoice, Product, etc.)
     * @param entityId ID of the entity
     * @param details Human-readable details
     * @param dataHash Hash of the data being recorded
     * @return entryId The created entry ID
     */
    function logEntry(
        address user,
        string memory userName,
        AuditAction action,
        string memory entityType,
        uint256 entityId,
        string memory details,
        bytes32 dataHash
    ) external onlyAuthorized withinDailyLimit returns (uint256) {
        _entryIdCounter++;
        uint256 entryId = _entryIdCounter;

        _entries[entryId] = AuditEntry({
            id: entryId,
            user: user,
            userName: userName,
            action: action,
            entityType: entityType,
            entityId: entityId,
            details: details,
            dataHash: dataHash,
            timestamp: block.timestamp,
            blockNumber: block.number
        });

        _allEntryIds.push(entryId);
        _userEntries[user].push(entryId);
        _entityTypeEntries[entityType].push(entryId);
        _entityEntries[entityId].push(entryId);

        if (dataHash != bytes32(0)) {
            _hashToEntry[dataHash] = entryId;
        }

        emit AuditEntryCreated(
            entryId,
            user,
            action,
            entityType,
            entityId,
            dataHash
        );

        return entryId;
    }

    /**
     * @notice Log a CREATE action
     * @param entityType Entity type
     * @param entityId Entity ID
     * @param details Details
     * @return entryId Entry ID
     */
    function logCreate(
        string memory entityType,
        uint256 entityId,
        string memory details
    ) external onlyAuthorized withinDailyLimit returns (uint256) {
        return
            _createEntry(
                msg.sender,
                "System",
                AuditAction.CREATE,
                entityType,
                entityId,
                details
            );
    }

    /**
     * @notice Log an UPDATE action
     * @param entityType Entity type
     * @param entityId Entity ID
     * @param details Details
     * @return entryId Entry ID
     */
    function logUpdate(
        string memory entityType,
        uint256 entityId,
        string memory details
    ) external onlyAuthorized withinDailyLimit returns (uint256) {
        return
            _createEntry(
                msg.sender,
                "System",
                AuditAction.UPDATE,
                entityType,
                entityId,
                details
            );
    }

    /**
     * @notice Log a DELETE action
     * @param entityType Entity type
     * @param entityId Entity ID
     * @param details Details
     * @return entryId Entry ID
     */
    function logDelete(
        string memory entityType,
        uint256 entityId,
        string memory details
    ) external onlyAuthorized withinDailyLimit returns (uint256) {
        return
            _createEntry(
                msg.sender,
                "System",
                AuditAction.DELETE,
                entityType,
                entityId,
                details
            );
    }

    /**
     * @notice Log a STATUS_CHANGE action
     * @param entityType Entity type
     * @param entityId Entity ID
     * @param details Details (should include old and new status)
     * @return entryId Entry ID
     */
    function logStatusChange(
        string memory entityType,
        uint256 entityId,
        string memory details
    ) external onlyAuthorized withinDailyLimit returns (uint256) {
        return
            _createEntry(
                msg.sender,
                "System",
                AuditAction.STATUS_CHANGE,
                entityType,
                entityId,
                details
            );
    }

    /**
     * @notice Log a TRANSFER action
     * @param entityType Entity type
     * @param entityId Entity ID
     * @param details Details (should include from and to)
     * @return entryId Entry ID
     */
    function logTransfer(
        string memory entityType,
        uint256 entityId,
        string memory details
    ) external onlyAuthorized withinDailyLimit returns (uint256) {
        return
            _createEntry(
                msg.sender,
                "System",
                AuditAction.TRANSFER,
                entityType,
                entityId,
                details
            );
    }

    /**
     * @notice Log a VERIFICATION action
     * @param entityType Entity type
     * @param entityId Entity ID
     * @param details Details
     * @param dataHash Verification hash
     * @return entryId Entry ID
     */
    function logVerification(
        string memory entityType,
        uint256 entityId,
        string memory details,
        bytes32 dataHash
    ) external onlyAuthorized withinDailyLimit returns (uint256) {
        _entryIdCounter++;
        uint256 entryId = _entryIdCounter;

        _entries[entryId] = AuditEntry({
            id: entryId,
            user: msg.sender,
            userName: "System",
            action: AuditAction.VERIFICATION,
            entityType: entityType,
            entityId: entityId,
            details: details,
            dataHash: dataHash,
            timestamp: block.timestamp,
            blockNumber: block.number
        });

        _allEntryIds.push(entryId);
        _userEntries[msg.sender].push(entryId);
        _entityTypeEntries[entityType].push(entryId);
        _entityEntries[entityId].push(entryId);
        _hashToEntry[dataHash] = entryId;

        emit AuditEntryCreated(
            entryId,
            msg.sender,
            AuditAction.VERIFICATION,
            entityType,
            entityId,
            dataHash
        );

        return entryId;
    }

    /**
     * @notice Batch log multiple entries
     * @param users Array of user addresses
     * @param userNames Array of user names
     * @param actions Array of actions
     * @param entityTypes Array of entity types
     * @param entityIds Array of entity IDs
     * @param detailsArray Array of details
     */
    function batchLogEntries(
        address[] memory users,
        string[] memory userNames,
        AuditAction[] memory actions,
        string[] memory entityTypes,
        uint256[] memory entityIds,
        string[] memory detailsArray
    ) external onlyAdmin {
        require(
            users.length == userNames.length &&
                users.length == actions.length &&
                users.length == entityTypes.length &&
                users.length == entityIds.length &&
                users.length == detailsArray.length,
            "AuditLog: array length mismatch"
        );

        for (uint256 i = 0; i < users.length; i++) {
            _createEntry(
                users[i],
                userNames[i],
                actions[i],
                entityTypes[i],
                entityIds[i],
                detailsArray[i]
            );
        }
    }

    // ============ Verification Functions ============

    /**
     * @notice Verify a data hash exists
     * @param dataHash Hash to verify
     * @return bool True if hash exists
     */
    function verifyHash(bytes32 dataHash) external view returns (bool) {
        return _hashToEntry[dataHash] != 0;
    }

    /**
     * @notice Get entry by data hash
     * @param dataHash Data hash
     * @return AuditEntry Entry data
     */
    function getEntryByHash(
        bytes32 dataHash
    ) external view returns (AuditEntry memory) {
        uint256 entryId = _hashToEntry[dataHash];
        require(entryId != 0, "AuditLog: hash not found");
        return _entries[entryId];
    }

    /**
     * @notice Verify entry integrity
     * @param entryId Entry ID
     * @param providedHash Hash to verify against
     * @return bool True if valid
     */
    function verifyEntryIntegrity(
        uint256 entryId,
        bytes32 providedHash
    ) external view entryExists(entryId) returns (bool) {
        return _entries[entryId].dataHash == providedHash;
    }

    // ============ View Functions ============

    /**
     * @notice Get audit entry by ID
     * @param entryId Entry ID
     * @return AuditEntry Entry data
     */
    function getEntry(
        uint256 entryId
    ) external view entryExists(entryId) returns (AuditEntry memory) {
        return _entries[entryId];
    }

    /**
     * @notice Get entries by user
     * @param user User address
     * @return uint256[] Array of entry IDs
     */
    function getEntriesByUser(
        address user
    ) external view returns (uint256[] memory) {
        return _userEntries[user];
    }

    /**
     * @notice Get entries by entity type
     * @param entityType Entity type
     * @return uint256[] Array of entry IDs
     */
    function getEntriesByEntityType(
        string memory entityType
    ) external view returns (uint256[] memory) {
        return _entityTypeEntries[entityType];
    }

    /**
     * @notice Get entries by entity ID
     * @param entityId Entity ID
     * @return uint256[] Array of entry IDs
     */
    function getEntriesByEntityId(
        uint256 entityId
    ) external view returns (uint256[] memory) {
        return _entityEntries[entityId];
    }

    /**
     * @notice Get all entry IDs
     * @return uint256[] Array of all entry IDs
     */
    function getAllEntryIds() external view returns (uint256[] memory) {
        return _allEntryIds;
    }

    /**
     * @notice Get total entry count
     * @return uint256 Total entries
     */
    function getEntryCount() external view returns (uint256) {
        return _allEntryIds.length;
    }

    /**
     * @notice Get recent entries
     * @param count Number of entries to return
     * @return AuditEntry[] Array of entries
     */
    function getRecentEntries(
        uint256 count
    ) external view returns (AuditEntry[] memory) {
        uint256 total = _allEntryIds.length;
        uint256 resultCount = count > total ? total : count;
        AuditEntry[] memory result = new AuditEntry[](resultCount);

        for (uint256 i = 0; i < resultCount; i++) {
            result[i] = _entries[_allEntryIds[total - 1 - i]];
        }

        return result;
    }

    /**
     * @notice Get entries within a time range
     * @param fromTimestamp Start timestamp
     * @param toTimestamp End timestamp
     * @return uint256[] Array of entry IDs
     */
    function getEntriesInRange(
        uint256 fromTimestamp,
        uint256 toTimestamp
    ) external view returns (uint256[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < _allEntryIds.length; i++) {
            uint256 ts = _entries[_allEntryIds[i]].timestamp;
            if (ts >= fromTimestamp && ts <= toTimestamp) {
                count++;
            }
        }

        uint256[] memory result = new uint256[](count);
        uint256 index = 0;
        for (uint256 i = 0; i < _allEntryIds.length; i++) {
            uint256 ts = _entries[_allEntryIds[i]].timestamp;
            if (ts >= fromTimestamp && ts <= toTimestamp) {
                result[index] = _allEntryIds[i];
                index++;
            }
        }

        return result;
    }

    /**
     * @notice Get entries by action type
     * @param action Action type
     * @return uint256[] Array of entry IDs
     */
    function getEntriesByAction(
        AuditAction action
    ) external view returns (uint256[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < _allEntryIds.length; i++) {
            if (_entries[_allEntryIds[i]].action == action) {
                count++;
            }
        }

        uint256[] memory result = new uint256[](count);
        uint256 index = 0;
        for (uint256 i = 0; i < _allEntryIds.length; i++) {
            if (_entries[_allEntryIds[i]].action == action) {
                result[index] = _allEntryIds[i];
                index++;
            }
        }

        return result;
    }

    /**
     * @notice Get audit statistics
     * @return total Total entries
     * @return today Entries created today
     * @return uniqueUsers Unique users logged
     * @return withHashes Entries with data hashes
     */
    function getAuditStats()
        external
        view
        returns (
            uint256 total,
            uint256 today,
            uint256 uniqueUsers,
            uint256 withHashes
        )
    {
        total = _allEntryIds.length;

        uint256 todayStart = (block.timestamp / 1 days) * 1 days;
        uint256 todayCount = 0;
        uint256 hashCount = 0;

        for (uint256 i = 0; i < _allEntryIds.length; i++) {
            AuditEntry storage entry = _entries[_allEntryIds[i]];
            if (entry.timestamp >= todayStart) {
                todayCount++;
            }
            if (entry.dataHash != bytes32(0)) {
                hashCount++;
            }
        }

        // Approximate unique users based on entry count
        uint256 userCount = total > 100 ? total / 10 : (total > 0 ? total : 1);

        return (total, todayCount, userCount, hashCount);
    }

    // ============ Admin Functions ============

    /**
     * @notice Authorize a module to write to audit log
     * @param module Module address
     */
    function authorizeModule(address module) external onlyAdmin {
        require(module != address(0), "AuditLog: invalid module address");
        require(
            !authorizedModules[module],
            "AuditLog: module already authorized"
        );

        authorizedModules[module] = true;
        emit ModuleAuthorized(module, msg.sender);
    }

    /**
     * @notice Deauthorize a module
     * @param module Module address
     */
    function deauthorizeModule(address module) external onlyAdmin {
        require(authorizedModules[module], "AuditLog: module not authorized");

        authorizedModules[module] = false;
        emit ModuleDeauthorized(module, msg.sender);
    }

    /**
     * @notice Update daily limit per user
     * @param newLimit New limit (0 for unlimited)
     */
    function setDailyLimit(uint256 newLimit) external onlyAdmin {
        uint256 previousLimit = dailyLimitPerUser;
        dailyLimitPerUser = newLimit;
        emit DailyLimitUpdated(previousLimit, newLimit);
    }

    // ============ Internal Functions ============

    function _createEntry(
        address user,
        string memory userName,
        AuditAction action,
        string memory entityType,
        uint256 entityId,
        string memory details
    ) internal returns (uint256) {
        _entryIdCounter++;
        uint256 entryId = _entryIdCounter;

        bytes32 dataHash = keccak256(
            abi.encodePacked(
                entryId,
                user,
                action,
                entityType,
                entityId,
                block.timestamp
            )
        );

        _entries[entryId] = AuditEntry({
            id: entryId,
            user: user,
            userName: userName,
            action: action,
            entityType: entityType,
            entityId: entityId,
            details: details,
            dataHash: dataHash,
            timestamp: block.timestamp,
            blockNumber: block.number
        });

        _allEntryIds.push(entryId);
        _userEntries[user].push(entryId);
        _entityTypeEntries[entityType].push(entryId);
        _entityEntries[entityId].push(entryId);
        _hashToEntry[dataHash] = entryId;

        emit AuditEntryCreated(
            entryId,
            user,
            action,
            entityType,
            entityId,
            dataHash
        );

        return entryId;
    }
}

contracts/BlockERPCore.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "./interfaces/IBlockERP.sol";

/**
 * @title BlockERPCore
 * @author BlockERP Team
 * @notice Main contract for BlockERP system - handles access control and registry
 * @dev Implements role-based access control and serves as the central registry
 */
contract BlockERPCore is IAccessControl {
    // ============ State Variables ============

    /// @notice Contract owner address
    address public owner;

    /// @notice Contract deployment timestamp
    uint256 public deployedAt;

    /// @notice System pause state
    bool public paused;

    /// @notice Mapping of addresses to roles
    mapping(address => Role) private _roles;

    /// @notice Mapping of registered modules
    mapping(string => address) public modules;

    /// @notice Array of all users with roles
    address[] public users;

    /// @notice Mapping to check if address is registered
    mapping(address => bool) public isRegistered;

    /// @notice Company information
    struct CompanyInfo {
        string name;
        string registrationNumber;
        string country;
        string website;
        bool isVerified;
    }

    CompanyInfo public company;

    // ============ Events ============

    event ModuleRegistered(string indexed moduleName, address moduleAddress);
    event ModuleUpdated(
        string indexed moduleName,
        address oldAddress,
        address newAddress
    );
    event SystemPaused(address indexed by);
    event SystemUnpaused(address indexed by);
    event CompanyInfoUpdated(string name, address indexed updatedBy);
    event OwnershipTransferred(
        address indexed previousOwner,
        address indexed newOwner
    );

    // ============ Modifiers ============

    modifier onlyOwner() {
        require(msg.sender == owner, "BlockERPCore: caller is not the owner");
        _;
    }

    modifier onlyAdmin() {
        require(
            _roles[msg.sender] == Role.ADMIN || msg.sender == owner,
            "BlockERPCore: caller is not admin"
        );
        _;
    }

    modifier onlyManagerOrAbove() {
        require(
            _roles[msg.sender] >= Role.MANAGER || msg.sender == owner,
            "BlockERPCore: insufficient permissions"
        );
        _;
    }

    modifier whenNotPaused() {
        require(!paused, "BlockERPCore: system is paused");
        _;
    }

    modifier validAddress(address _addr) {
        require(_addr != address(0), "BlockERPCore: invalid address");
        _;
    }

    // ============ Constructor ============

    constructor(
        string memory _companyName,
        string memory _registrationNumber,
        string memory _country
    ) {
        owner = msg.sender;
        deployedAt = block.timestamp;
        _roles[msg.sender] = Role.ADMIN;
        users.push(msg.sender);
        isRegistered[msg.sender] = true;

        company = CompanyInfo({
            name: _companyName,
            registrationNumber: _registrationNumber,
            country: _country,
            website: "",
            isVerified: false
        });

        emit RoleGranted(msg.sender, Role.ADMIN, msg.sender);
    }

    // ============ Access Control Functions ============

    /**
     * @notice Grant a role to an account
     * @param account The address to grant the role to
     * @param role The role to grant
     */
    function grantRole(
        address account,
        Role role
    ) external override onlyAdmin validAddress(account) whenNotPaused {
        require(role != Role.NONE, "BlockERPCore: cannot grant NONE role");

        if (!isRegistered[account]) {
            users.push(account);
            isRegistered[account] = true;
        }

        _roles[account] = role;
        emit RoleGranted(account, role, msg.sender);
    }

    /**
     * @notice Revoke role from an account
     * @param account The address to revoke the role from
     */
    function revokeRole(
        address account
    ) external override onlyAdmin validAddress(account) {
        require(account != owner, "BlockERPCore: cannot revoke owner role");
        require(
            _roles[account] != Role.NONE,
            "BlockERPCore: account has no role"
        );

        Role previousRole = _roles[account];
        _roles[account] = Role.NONE;
        emit RoleRevoked(account, previousRole, msg.sender);
    }

    /**
     * @notice Check if account has a specific role or higher
     * @param account The address to check
     * @param role The minimum role required
     * @return bool True if account has the role or higher
     */
    function hasRole(
        address account,
        Role role
    ) external view override returns (bool) {
        if (account == owner) return true;
        return _roles[account] >= role;
    }

    /**
     * @notice Get the role of an account
     * @param account The address to query
     * @return Role The role of the account
     */
    function getRole(address account) external view override returns (Role) {
        if (account == owner) return Role.ADMIN;
        return _roles[account];
    }

    /**
     * @notice Get all registered users
     * @return address[] Array of user addresses
     */
    function getAllUsers() external view returns (address[] memory) {
        return users;
    }

    /**
     * @notice Get total number of users
     * @return uint256 Number of registered users
     */
    function getUserCount() external view returns (uint256) {
        return users.length;
    }

    // ============ Module Registry Functions ============

    /**
     * @notice Register a new module
     * @param moduleName The name identifier for the module
     * @param moduleAddress The contract address of the module
     */
    function registerModule(
        string memory moduleName,
        address moduleAddress
    ) external onlyOwner validAddress(moduleAddress) {
        require(
            modules[moduleName] == address(0),
            "BlockERPCore: module already registered"
        );
        modules[moduleName] = moduleAddress;
        emit ModuleRegistered(moduleName, moduleAddress);
    }

    /**
     * @notice Update an existing module address
     * @param moduleName The name identifier for the module
     * @param newAddress The new contract address
     */
    function updateModule(
        string memory moduleName,
        address newAddress
    ) external onlyOwner validAddress(newAddress) {
        require(
            modules[moduleName] != address(0),
            "BlockERPCore: module not registered"
        );
        address oldAddress = modules[moduleName];
        modules[moduleName] = newAddress;
        emit ModuleUpdated(moduleName, oldAddress, newAddress);
    }

    /**
     * @notice Get module address by name
     * @param moduleName The name identifier for the module
     * @return address The module contract address
     */
    function getModule(
        string memory moduleName
    ) external view returns (address) {
        return modules[moduleName];
    }

    // ============ System Control Functions ============

    /**
     * @notice Pause the entire system
     */
    function pause() external onlyAdmin {
        paused = true;
        emit SystemPaused(msg.sender);
    }

    /**
     * @notice Unpause the system
     */
    function unpause() external onlyAdmin {
        paused = false;
        emit SystemUnpaused(msg.sender);
    }

    /**
     * @notice Update company information
     * @param _name Company name
     * @param _website Company website
     */
    function updateCompanyInfo(
        string memory _name,
        string memory _website
    ) external onlyAdmin {
        company.name = _name;
        company.website = _website;
        emit CompanyInfoUpdated(_name, msg.sender);
    }

    /**
     * @notice Verify company (owner only)
     */
    function verifyCompany() external onlyOwner {
        company.isVerified = true;
    }

    /**
     * @notice Transfer ownership of the contract
     * @param newOwner Address of the new owner
     */
    function transferOwnership(
        address newOwner
    ) external onlyOwner validAddress(newOwner) {
        require(newOwner != owner, "BlockERPCore: new owner is current owner");

        address previousOwner = owner;
        owner = newOwner;
        _roles[newOwner] = Role.ADMIN;

        if (!isRegistered[newOwner]) {
            users.push(newOwner);
            isRegistered[newOwner] = true;
        }

        emit OwnershipTransferred(previousOwner, newOwner);
        emit RoleGranted(newOwner, Role.ADMIN, previousOwner);
    }

    // ============ View Functions ============

    /**
     * @notice Get complete company information
     * @return CompanyInfo struct
     */
    function getCompanyInfo() external view returns (CompanyInfo memory) {
        return company;
    }

    /**
     * @notice Get system status
     * @return isPaused Whether the system is paused
     * @return _deployedAt Deployment timestamp
     * @return userCount Number of users
     * @return _owner Contract owner address
     */
    function getSystemStatus()
        external
        view
        returns (
            bool isPaused,
            uint256 _deployedAt,
            uint256 userCount,
            address _owner
        )
    {
        return (paused, deployedAt, users.length, owner);
    }

    /**
     * @notice Check if caller has minimum required role
     * @param minRole Minimum role required
     * @return bool True if caller meets requirement
     */
    function checkAccess(Role minRole) external view returns (bool) {
        if (msg.sender == owner) return true;
        return _roles[msg.sender] >= minRole;
    }
}

contracts/interfaces/IBlockERP.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @title IBlockERP Interface
 * @notice Core interfaces for the BlockERP system
 * @dev All modules must implement relevant interfaces for interoperability
 */

/// @notice Role-based access control interface
interface IAccessControl {
    enum Role {
        NONE,
        VIEWER,
        MANAGER,
        ADMIN
    }

    event RoleGranted(
        address indexed account,
        Role role,
        address indexed grantor
    );
    event RoleRevoked(
        address indexed account,
        Role role,
        address indexed revoker
    );

    function grantRole(address account, Role role) external;

    function revokeRole(address account) external;

    function hasRole(address account, Role role) external view returns (bool);

    function getRole(address account) external view returns (Role);
}

/// @notice Order status enumeration
interface IOrderTypes {
    enum OrderStatus {
        PENDING,
        PROCESSING,
        SHIPPED,
        DELIVERED,
        CANCELLED,
        REFUNDED
    }

    struct OrderItem {
        uint256 productId;
        string productName;
        string sku;
        uint256 quantity;
        uint256 unitPrice;
        uint256 totalPrice;
    }

    struct Order {
        uint256 id;
        uint256 customerId;
        string customerName;
        OrderItem[] items;
        uint256 totalAmount;
        OrderStatus status;
        uint256 createdAt;
        uint256 updatedAt;
        string blockchainHash;
        bool verified;
    }
}

/// @notice Invoice status enumeration
interface IInvoiceTypes {
    enum InvoiceStatus {
        DRAFT,
        SENT,
        PAID,
        OVERDUE,
        CANCELLED,
        REFUNDED
    }

    struct InvoiceItem {
        uint256 productId;
        string description;
        uint256 quantity;
        uint256 unitPrice;
        uint256 totalPrice;
    }

    struct Invoice {
        uint256 id;
        uint256 orderId;
        uint256 customerId;
        string customerName;
        InvoiceItem[] items;
        uint256 subtotal;
        uint256 taxRate;
        uint256 taxAmount;
        uint256 discountRate;
        uint256 discountAmount;
        uint256 totalAmount;
        InvoiceStatus status;
        uint256 issueDate;
        uint256 dueDate;
        uint256 paidDate;
        string blockchainHash;
    }
}

/// @notice Product/Inventory types
interface IInventoryTypes {
    enum ProductStatus {
        IN_STOCK,
        LOW_STOCK,
        OUT_OF_STOCK,
        DISCONTINUED
    }

    struct Product {
        uint256 id;
        string name;
        string sku;
        string category;
        uint256 price;
        uint256 stock;
        uint256 reorderLevel;
        ProductStatus status;
        string batchNumber;
        uint256 manufactureDate;
        uint256 expiryDate;
        string qrCodeHash;
        bool isActive;
    }

    struct StockMovement {
        uint256 productId;
        int256 quantityChange;
        string movementType; // "IN", "OUT", "ADJUSTMENT"
        string reason;
        uint256 timestamp;
        address initiator;
    }
}

/// @notice Customer types
interface ICustomerTypes {
    enum CustomerStatus {
        LEAD,
        PROSPECT,
        ACTIVE,
        INACTIVE,
        CHURNED
    }

    enum CustomerSegment {
        INDIVIDUAL,
        STARTUP,
        BUSINESS,
        ENTERPRISE
    }

    struct Customer {
        uint256 id;
        string name;
        string email;
        string company;
        CustomerStatus status;
        CustomerSegment segment;
        uint256 lifetimeValue;
        uint256 createdAt;
        uint256 lastOrderAt;
        bool isActive;
    }
}

/// @notice Audit log types
interface IAuditTypes {
    enum AuditAction {
        CREATE,
        UPDATE,
        DELETE,
        STATUS_CHANGE,
        TRANSFER,
        VERIFICATION
    }

    struct AuditEntry {
        uint256 id;
        address user;
        string userName;
        AuditAction action;
        string entityType;
        uint256 entityId;
        string details;
        bytes32 dataHash;
        uint256 timestamp;
        uint256 blockNumber;
    }
}

/// @notice Supply chain tracking types
interface ISupplyChainTypes {
    enum TrackingStatus {
        MANUFACTURED,
        IN_TRANSIT,
        AT_WAREHOUSE,
        QUALITY_CHECK,
        READY_FOR_DISPATCH,
        DISPATCHED,
        IN_DELIVERY,
        DELIVERED,
        RETURNED
    }

    struct TrackingEvent {
        uint256 productId;
        TrackingStatus status;
        string location;
        string handler;
        string notes;
        uint256 timestamp;
        bytes32 previousHash;
        bytes32 currentHash;
    }

    struct SupplyChainRecord {
        uint256 productId;
        string origin;
        string destination;
        TrackingEvent[] events;
        uint256 createdAt;
        bool isComplete;
    }
}

contracts/InventoryManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "./interfaces/IBlockERP.sol";
import "./BlockERPCore.sol";

/**
 * @title InventoryManager
 * @author BlockERP Team
 * @notice Manages products and inventory with stock tracking, reorder alerts, and QR codes
 * @dev Integrates with BlockERPCore for access control
 */
contract InventoryManager is IInventoryTypes {
    // ============ State Variables ============

    /// @notice Reference to core contract
    BlockERPCore public immutable core;

    /// @notice Product counter for unique IDs
    uint256 private _productIdCounter;

    /// @notice Mapping of product ID to Product data
    mapping(uint256 => Product) private _products;

    /// @notice Mapping of SKU to product ID
    mapping(string => uint256) private _skuToProduct;

    /// @notice Mapping of category to product IDs
    mapping(string => uint256[]) private _categoryProducts;

    /// @notice Array of all product IDs
    uint256[] private _allProductIds;

    /// @notice Stock movement history per product
    mapping(uint256 => StockMovement[]) private _stockHistory;

    /// @notice QR code hash to product ID mapping
    mapping(bytes32 => uint256) private _qrToProduct;

    /// @notice All categories
    string[] private _categories;
    mapping(string => bool) private _categoryExists;

    /// @notice Inventory statistics
    struct InventoryStats {
        uint256 totalProducts;
        uint256 activeProducts;
        uint256 inStockProducts;
        uint256 lowStockProducts;
        uint256 outOfStockProducts;
        uint256 discontinuedProducts;
        uint256 totalValue;
        uint256 totalUnits;
    }

    InventoryStats public stats;

    /// @notice Reorder configuration
    struct ReorderConfig {
        bool autoReorder;
        uint256 defaultReorderQuantity;
        address reorderNotificationAddress;
    }

    ReorderConfig public reorderConfig;

    // ============ Events ============

    event ProductCreated(
        uint256 indexed productId,
        string name,
        string sku,
        string category,
        string qrCodeHash
    );

    event ProductUpdated(
        uint256 indexed productId,
        string field,
        address indexed updatedBy
    );

    event StockUpdated(
        uint256 indexed productId,
        int256 quantityChange,
        string movementType,
        uint256 newStock,
        address indexed updatedBy
    );

    event StockStatusChanged(
        uint256 indexed productId,
        ProductStatus previousStatus,
        ProductStatus newStatus
    );

    event LowStockAlert(
        uint256 indexed productId,
        string sku,
        uint256 currentStock,
        uint256 reorderLevel
    );

    event ProductDiscontinued(
        uint256 indexed productId,
        string reason,
        address indexed discontinuedBy
    );

    event CategoryCreated(string category);

    event QRCodeGenerated(uint256 indexed productId, bytes32 qrHash);

    // ============ Modifiers ============

    modifier onlyAdmin() {
        require(
            core.hasRole(msg.sender, IAccessControl.Role.ADMIN),
            "InventoryManager: caller is not admin"
        );
        _;
    }

    modifier onlyManagerOrAbove() {
        require(
            core.hasRole(msg.sender, IAccessControl.Role.MANAGER),
            "InventoryManager: insufficient permissions"
        );
        _;
    }

    modifier whenNotPaused() {
        require(!core.paused(), "InventoryManager: system is paused");
        _;
    }

    modifier productExists(uint256 productId) {
        require(
            _products[productId].id != 0,
            "InventoryManager: product does not exist"
        );
        _;
    }

    modifier productActive(uint256 productId) {
        require(
            _products[productId].isActive,
            "InventoryManager: product not active"
        );
        _;
    }

    // ============ Constructor ============

    constructor(address _coreAddress) {
        require(
            _coreAddress != address(0),
            "InventoryManager: invalid core address"
        );
        core = BlockERPCore(_coreAddress);
        _productIdCounter = 100; // Start from 100 for readability

        reorderConfig = ReorderConfig({
            autoReorder: false,
            defaultReorderQuantity: 100,
            reorderNotificationAddress: address(0)
        });
    }

    // ============ Product Management Functions ============

    /**
     * @notice Create a new product
     * @param name Product name
     * @param sku Unique SKU code
     * @param category Product category
     * @param price Product price (in smallest unit)
     * @param initialStock Initial stock quantity
     * @param reorderLevel Stock level to trigger reorder alert
     * @param batchNumber Manufacturer batch number
     * @param manufactureDate Manufacturing date timestamp
     * @param expiryDate Expiry date timestamp (0 if no expiry)
     * @return productId The created product ID
     */
    function createProduct(
        string memory name,
        string memory sku,
        string memory category,
        uint256 price,
        uint256 initialStock,
        uint256 reorderLevel,
        string memory batchNumber,
        uint256 manufactureDate,
        uint256 expiryDate
    ) external onlyManagerOrAbove whenNotPaused returns (uint256) {
        require(bytes(name).length > 0, "InventoryManager: name required");
        require(bytes(sku).length > 0, "InventoryManager: SKU required");
        require(
            _skuToProduct[sku] == 0,
            "InventoryManager: SKU already exists"
        );
        require(price > 0, "InventoryManager: price must be positive");

        _productIdCounter++;
        uint256 productId = _productIdCounter;

        // Generate QR code hash
        bytes32 qrHash = keccak256(
            abi.encodePacked(productId, sku, name, block.timestamp)
        );

        // Determine initial status
        ProductStatus initialStatus;
        if (initialStock == 0) {
            initialStatus = ProductStatus.OUT_OF_STOCK;
            stats.outOfStockProducts++;
        } else if (initialStock <= reorderLevel) {
            initialStatus = ProductStatus.LOW_STOCK;
            stats.lowStockProducts++;
        } else {
            initialStatus = ProductStatus.IN_STOCK;
            stats.inStockProducts++;
        }

        _products[productId] = Product({
            id: productId,
            name: name,
            sku: sku,
            category: category,
            price: price,
            stock: initialStock,
            reorderLevel: reorderLevel,
            status: initialStatus,
            batchNumber: batchNumber,
            manufactureDate: manufactureDate,
            expiryDate: expiryDate,
            qrCodeHash: _bytes32ToString(qrHash),
            isActive: true
        });

        _skuToProduct[sku] = productId;
        _allProductIds.push(productId);
        _qrToProduct[qrHash] = productId;

        // Add to category
        if (!_categoryExists[category]) {
            _categories.push(category);
            _categoryExists[category] = true;
            emit CategoryCreated(category);
        }
        _categoryProducts[category].push(productId);

        // Record initial stock movement
        if (initialStock > 0) {
            _stockHistory[productId].push(
                StockMovement({
                    productId: productId,
                    quantityChange: int256(initialStock),
                    movementType: "IN",
                    reason: "Initial stock",
                    timestamp: block.timestamp,
                    initiator: msg.sender
                })
            );
        }

        // Update stats
        stats.totalProducts++;
        stats.activeProducts++;
        stats.totalUnits += initialStock;
        stats.totalValue += price * initialStock;

        emit ProductCreated(
            productId,
            name,
            sku,
            category,
            _products[productId].qrCodeHash
        );
        emit QRCodeGenerated(productId, qrHash);

        // Check for low stock alert
        if (initialStatus == ProductStatus.LOW_STOCK) {
            emit LowStockAlert(productId, sku, initialStock, reorderLevel);
        }

        return productId;
    }

    /**
     * @notice Update product information
     * @param productId Product ID
     * @param name New name
     * @param price New price
     * @param reorderLevel New reorder level
     */
    function updateProduct(
        uint256 productId,
        string memory name,
        uint256 price,
        uint256 reorderLevel
    )
        external
        onlyManagerOrAbove
        whenNotPaused
        productExists(productId)
        productActive(productId)
    {
        Product storage product = _products[productId];

        // Update value stat
        stats.totalValue -= product.price * product.stock;

        if (bytes(name).length > 0) {
            product.name = name;
            emit ProductUpdated(productId, "name", msg.sender);
        }
        if (price > 0) {
            product.price = price;
            emit ProductUpdated(productId, "price", msg.sender);
        }
        if (reorderLevel > 0) {
            product.reorderLevel = reorderLevel;
            emit ProductUpdated(productId, "reorderLevel", msg.sender);

            // Check if status needs update
            _updateStockStatus(productId);
        }

        // Recalculate value stat
        stats.totalValue += product.price * product.stock;
    }

    /**
     * @notice Add stock (restock)
     * @param productId Product ID
     * @param quantity Quantity to add
     * @param reason Reason for stock addition
     */
    function addStock(
        uint256 productId,
        uint256 quantity,
        string memory reason
    )
        external
        onlyManagerOrAbove
        whenNotPaused
        productExists(productId)
        productActive(productId)
    {
        require(quantity > 0, "InventoryManager: quantity must be positive");

        Product storage product = _products[productId];

        product.stock += quantity;
        stats.totalUnits += quantity;
        stats.totalValue += product.price * quantity;

        // Record stock movement
        _stockHistory[productId].push(
            StockMovement({
                productId: productId,
                quantityChange: int256(quantity),
                movementType: "IN",
                reason: reason,
                timestamp: block.timestamp,
                initiator: msg.sender
            })
        );

        _updateStockStatus(productId);

        emit StockUpdated(
            productId,
            int256(quantity),
            "IN",
            product.stock,
            msg.sender
        );
    }

    /**
     * @notice Remove stock (sale, damage, etc.)
     * @param productId Product ID
     * @param quantity Quantity to remove
     * @param reason Reason for stock removal
     */
    function removeStock(
        uint256 productId,
        uint256 quantity,
        string memory reason
    )
        external
        onlyManagerOrAbove
        whenNotPaused
        productExists(productId)
        productActive(productId)
    {
        require(quantity > 0, "InventoryManager: quantity must be positive");

        Product storage product = _products[productId];
        require(
            product.stock >= quantity,
            "InventoryManager: insufficient stock"
        );

        product.stock -= quantity;
        stats.totalUnits -= quantity;
        stats.totalValue -= product.price * quantity;

        // Record stock movement
        _stockHistory[productId].push(
            StockMovement({
                productId: productId,
                quantityChange: -int256(quantity),
                movementType: "OUT",
                reason: reason,
                timestamp: block.timestamp,
                initiator: msg.sender
            })
        );

        _updateStockStatus(productId);

        emit StockUpdated(
            productId,
            -int256(quantity),
            "OUT",
            product.stock,
            msg.sender
        );
    }

    /**
     * @notice Adjust stock (inventory correction)
     * @param productId Product ID
     * @param newStock New stock quantity (absolute)
     * @param reason Reason for adjustment
     */
    function adjustStock(
        uint256 productId,
        uint256 newStock,
        string memory reason
    ) external onlyAdmin whenNotPaused productExists(productId) {
        Product storage product = _products[productId];

        int256 difference = int256(newStock) - int256(product.stock);

        // Update stats
        if (difference > 0) {
            stats.totalUnits += uint256(difference);
            stats.totalValue += product.price * uint256(difference);
        } else if (difference < 0) {
            stats.totalUnits -= uint256(-difference);
            stats.totalValue -= product.price * uint256(-difference);
        }

        product.stock = newStock;

        // Record stock movement
        _stockHistory[productId].push(
            StockMovement({
                productId: productId,
                quantityChange: difference,
                movementType: "ADJUSTMENT",
                reason: reason,
                timestamp: block.timestamp,
                initiator: msg.sender
            })
        );

        _updateStockStatus(productId);

        emit StockUpdated(
            productId,
            difference,
            "ADJUSTMENT",
            newStock,
            msg.sender
        );
    }

    /**
     * @notice Discontinue a product
     * @param productId Product ID
     * @param reason Reason for discontinuing
     */
    function discontinueProduct(
        uint256 productId,
        string memory reason
    ) external onlyAdmin productExists(productId) {
        Product storage product = _products[productId];
        require(
            product.status != ProductStatus.DISCONTINUED,
            "InventoryManager: already discontinued"
        );

        ProductStatus previousStatus = product.status;
        product.status = ProductStatus.DISCONTINUED;
        product.isActive = false;

        // Update stats
        _decrementStatusCounter(previousStatus);
        stats.discontinuedProducts++;
        stats.activeProducts--;

        emit ProductDiscontinued(productId, reason, msg.sender);
        emit StockStatusChanged(
            productId,
            previousStatus,
            ProductStatus.DISCONTINUED
        );
    }

    /**
     * @notice Reactivate a discontinued product
     * @param productId Product ID
     */
    function reactivateProduct(
        uint256 productId
    ) external onlyAdmin productExists(productId) {
        Product storage product = _products[productId];
        require(
            product.status == ProductStatus.DISCONTINUED,
            "InventoryManager: not discontinued"
        );

        product.isActive = true;
        stats.discontinuedProducts--;
        stats.activeProducts++;

        _updateStockStatus(productId);
    }

    /**
     * @notice Generate new QR code for product
     * @param productId Product ID
     * @return qrHash New QR code hash
     */
    function regenerateQRCode(
        uint256 productId
    ) external onlyManagerOrAbove productExists(productId) returns (bytes32) {
        Product storage product = _products[productId];

        bytes32 newQrHash = keccak256(
            abi.encodePacked(
                productId,
                product.sku,
                product.name,
                block.timestamp,
                block.number
            )
        );

        product.qrCodeHash = _bytes32ToString(newQrHash);
        _qrToProduct[newQrHash] = productId;

        emit QRCodeGenerated(productId, newQrHash);

        return newQrHash;
    }

    // ============ View Functions ============

    /**
     * @notice Get product by ID
     * @param productId Product ID
     * @return Product struct data
     */
    function getProduct(
        uint256 productId
    ) external view productExists(productId) returns (Product memory) {
        return _products[productId];
    }

    /**
     * @notice Get product by SKU
     * @param sku Product SKU
     * @return Product struct data
     */
    function getProductBySKU(
        string memory sku
    ) external view returns (Product memory) {
        uint256 productId = _skuToProduct[sku];
        require(productId != 0, "InventoryManager: product not found");
        return _products[productId];
    }

    /**
     * @notice Get product by QR hash
     * @param qrHash QR code hash
     * @return Product struct data
     */
    function getProductByQR(
        bytes32 qrHash
    ) external view returns (Product memory) {
        uint256 productId = _qrToProduct[qrHash];
        require(productId != 0, "InventoryManager: product not found");
        return _products[productId];
    }

    /**
     * @notice Get stock history for a product
     * @param productId Product ID
     * @return StockMovement[] Array of movements
     */
    function getStockHistory(
        uint256 productId
    ) external view productExists(productId) returns (StockMovement[] memory) {
        return _stockHistory[productId];
    }

    /**
     * @notice Get products by category
     * @param category Category name
     * @return uint256[] Array of product IDs
     */
    function getProductsByCategory(
        string memory category
    ) external view returns (uint256[] memory) {
        return _categoryProducts[category];
    }

    /**
     * @notice Get all categories
     * @return string[] Array of category names
     */
    function getAllCategories() external view returns (string[] memory) {
        return _categories;
    }

    /**
     * @notice Get products by status
     * @param status Product status
     * @return uint256[] Array of product IDs
     */
    function getProductsByStatus(
        ProductStatus status
    ) external view returns (uint256[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < _allProductIds.length; i++) {
            if (_products[_allProductIds[i]].status == status) {
                count++;
            }
        }

        uint256[] memory result = new uint256[](count);
        uint256 index = 0;
        for (uint256 i = 0; i < _allProductIds.length; i++) {
            if (_products[_allProductIds[i]].status == status) {
                result[index] = _allProductIds[i];
                index++;
            }
        }

        return result;
    }

    /**
     * @notice Get low stock products
     * @return uint256[] Array of product IDs
     */
    function getLowStockProducts() external view returns (uint256[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < _allProductIds.length; i++) {
            Product storage product = _products[_allProductIds[i]];
            if (product.isActive && product.stock <= product.reorderLevel) {
                count++;
            }
        }

        uint256[] memory result = new uint256[](count);
        uint256 index = 0;
        for (uint256 i = 0; i < _allProductIds.length; i++) {
            Product storage product = _products[_allProductIds[i]];
            if (product.isActive && product.stock <= product.reorderLevel) {
                result[index] = _allProductIds[i];
                index++;
            }
        }

        return result;
    }

    /**
     * @notice Get expiring products
     * @param withinDays Number of days to check
     * @return uint256[] Array of product IDs
     */
    function getExpiringProducts(
        uint256 withinDays
    ) external view returns (uint256[] memory) {
        uint256 threshold = block.timestamp + (withinDays * 1 days);

        uint256 count = 0;
        for (uint256 i = 0; i < _allProductIds.length; i++) {
            Product storage product = _products[_allProductIds[i]];
            if (
                product.isActive &&
                product.expiryDate != 0 &&
                product.expiryDate <= threshold
            ) {
                count++;
            }
        }

        uint256[] memory result = new uint256[](count);
        uint256 index = 0;
        for (uint256 i = 0; i < _allProductIds.length; i++) {
            Product storage product = _products[_allProductIds[i]];
            if (
                product.isActive &&
                product.expiryDate != 0 &&
                product.expiryDate <= threshold
            ) {
                result[index] = _allProductIds[i];
                index++;
            }
        }

        return result;
    }

    /**
     * @notice Get all product IDs
     * @return uint256[] Array of all product IDs
     */
    function getAllProductIds() external view returns (uint256[] memory) {
        return _allProductIds;
    }

    /**
     * @notice Get inventory statistics
     * @return InventoryStats struct
     */
    function getInventoryStats() external view returns (InventoryStats memory) {
        return stats;
    }

    /**
     * @notice Check if SKU exists
     * @param sku SKU to check
     * @return bool True if exists
     */
    function skuExists(string memory sku) external view returns (bool) {
        return _skuToProduct[sku] != 0;
    }

    // ============ Configuration Functions ============

    /**
     * @notice Update reorder configuration
     * @param autoReorder Enable auto reorder notifications
     * @param defaultQuantity Default reorder quantity
     * @param notificationAddress Address to notify for reorders
     */
    function updateReorderConfig(
        bool autoReorder,
        uint256 defaultQuantity,
        address notificationAddress
    ) external onlyAdmin {
        reorderConfig.autoReorder = autoReorder;
        reorderConfig.defaultReorderQuantity = defaultQuantity;
        reorderConfig.reorderNotificationAddress = notificationAddress;
    }

    // ============ Internal Functions ============

    function _updateStockStatus(uint256 productId) internal {
        Product storage product = _products[productId];
        ProductStatus previousStatus = product.status;
        ProductStatus newStatus;

        if (product.stock == 0) {
            newStatus = ProductStatus.OUT_OF_STOCK;
        } else if (product.stock <= product.reorderLevel) {
            newStatus = ProductStatus.LOW_STOCK;
        } else {
            newStatus = ProductStatus.IN_STOCK;
        }

        if (previousStatus != newStatus) {
            _decrementStatusCounter(previousStatus);
            _incrementStatusCounter(newStatus);
            product.status = newStatus;

            emit StockStatusChanged(productId, previousStatus, newStatus);

            if (
                newStatus == ProductStatus.LOW_STOCK ||
                newStatus == ProductStatus.OUT_OF_STOCK
            ) {
                emit LowStockAlert(
                    productId,
                    product.sku,
                    product.stock,
                    product.reorderLevel
                );
            }
        }
    }

    function _decrementStatusCounter(ProductStatus status) internal {
        if (status == ProductStatus.IN_STOCK) stats.inStockProducts--;
        else if (status == ProductStatus.LOW_STOCK) stats.lowStockProducts--;
        else if (status == ProductStatus.OUT_OF_STOCK)
            stats.outOfStockProducts--;
    }

    function _incrementStatusCounter(ProductStatus status) internal {
        if (status == ProductStatus.IN_STOCK) stats.inStockProducts++;
        else if (status == ProductStatus.LOW_STOCK) stats.lowStockProducts++;
        else if (status == ProductStatus.OUT_OF_STOCK)
            stats.outOfStockProducts++;
    }

    function _bytes32ToString(
        bytes32 _bytes32
    ) internal pure returns (string memory) {
        bytes memory bytesArray = new bytes(66);
        bytesArray[0] = "0";
        bytesArray[1] = "x";
        for (uint256 i = 0; i < 32; i++) {
            bytesArray[2 + i * 2] = _toHexChar(uint8(_bytes32[i] >> 4));
            bytesArray[3 + i * 2] = _toHexChar(uint8(_bytes32[i] & 0x0f));
        }
        return string(bytesArray);
    }

    function _toHexChar(uint8 _value) internal pure returns (bytes1) {
        if (_value < 10) {
            return bytes1(_value + 48);
        } else {
            return bytes1(_value + 87);
        }
    }
}

contracts/InvoiceManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "./interfaces/IBlockERP.sol";
import "./BlockERPCore.sol";

/**
 * @title InvoiceManager
 * @author BlockERP Team
 * @notice Manages invoices with full lifecycle, payments, and blockchain verification
 * @dev Integrates with BlockERPCore for access control
 */
contract InvoiceManager is IInvoiceTypes {
    // ============ State Variables ============

    /// @notice Reference to core contract
    BlockERPCore public immutable core;

    /// @notice Invoice counter for unique IDs
    uint256 private _invoiceIdCounter;

    /// @notice Mapping of invoice ID to Invoice data
    mapping(uint256 => Invoice) private _invoices;

    /// @notice Mapping of invoice ID to items
    mapping(uint256 => InvoiceItem[]) private _invoiceItems;

    /// @notice Mapping of customer ID to their invoice IDs
    mapping(uint256 => uint256[]) private _customerInvoices;

    /// @notice Mapping of order ID to invoice ID
    mapping(uint256 => uint256) private _orderToInvoice;

    /// @notice Array of all invoice IDs
    uint256[] private _allInvoiceIds;

    /// @notice Payment records
    struct PaymentRecord {
        uint256 invoiceId;
        uint256 amount;
        string paymentMethod;
        string transactionRef;
        uint256 timestamp;
        address recordedBy;
    }

    /// @notice Mapping of invoice ID to payment records
    mapping(uint256 => PaymentRecord[]) private _paymentHistory;

    /// @notice Invoice statistics
    struct InvoiceStats {
        uint256 totalInvoices;
        uint256 draftInvoices;
        uint256 sentInvoices;
        uint256 paidInvoices;
        uint256 overdueInvoices;
        uint256 cancelledInvoices;
        uint256 totalValue;
        uint256 paidValue;
        uint256 overdueValue;
        uint256 pendingValue;
    }

    InvoiceStats public stats;

    // ============ Events ============

    event InvoiceCreated(
        uint256 indexed invoiceId,
        uint256 indexed customerId,
        uint256 indexed orderId,
        uint256 totalAmount,
        string blockchainHash
    );

    event InvoiceStatusUpdated(
        uint256 indexed invoiceId,
        InvoiceStatus previousStatus,
        InvoiceStatus newStatus,
        address indexed updatedBy
    );

    event InvoicePaid(
        uint256 indexed invoiceId,
        uint256 amount,
        string paymentMethod,
        address indexed recordedBy
    );

    event InvoiceSent(
        uint256 indexed invoiceId,
        address indexed sentBy,
        uint256 timestamp
    );

    event InvoiceOverdue(uint256 indexed invoiceId, uint256 daysOverdue);

    event PaymentRecorded(
        uint256 indexed invoiceId,
        uint256 amount,
        string transactionRef
    );

    // ============ Modifiers ============

    modifier onlyAdmin() {
        require(
            core.hasRole(msg.sender, IAccessControl.Role.ADMIN),
            "InvoiceManager: caller is not admin"
        );
        _;
    }

    modifier onlyManagerOrAbove() {
        require(
            core.hasRole(msg.sender, IAccessControl.Role.MANAGER),
            "InvoiceManager: insufficient permissions"
        );
        _;
    }

    modifier whenNotPaused() {
        require(!core.paused(), "InvoiceManager: system is paused");
        _;
    }

    modifier invoiceExists(uint256 invoiceId) {
        require(
            _invoices[invoiceId].id != 0,
            "InvoiceManager: invoice does not exist"
        );
        _;
    }

    // ============ Constructor ============

    constructor(address _coreAddress) {
        require(
            _coreAddress != address(0),
            "InvoiceManager: invalid core address"
        );
        core = BlockERPCore(_coreAddress);
        _invoiceIdCounter = 5000; // Start from 5000 for readability
    }

    // ============ Invoice Management Functions ============

    /**
     * @notice Create a new invoice
     * @param orderId Associated order ID (0 if standalone)
     * @param customerId Customer identifier
     * @param customerName Customer name
     * @param items Invoice line items
     * @param taxRate Tax rate in basis points (e.g., 850 = 8.5%)
     * @param discountRate Discount rate in basis points
     * @param dueDate Due date timestamp
     * @return invoiceId The created invoice ID
     */
    function createInvoice(
        uint256 orderId,
        uint256 customerId,
        string memory customerName,
        InvoiceItem[] memory items,
        uint256 taxRate,
        uint256 discountRate,
        uint256 dueDate
    ) external onlyManagerOrAbove whenNotPaused returns (uint256) {
        require(items.length > 0, "InvoiceManager: invoice must have items");
        require(
            dueDate > block.timestamp,
            "InvoiceManager: due date must be in future"
        );
        require(
            bytes(customerName).length > 0,
            "InvoiceManager: customer name required"
        );

        if (orderId != 0) {
            require(
                _orderToInvoice[orderId] == 0,
                "InvoiceManager: order already has invoice"
            );
        }

        _invoiceIdCounter++;
        uint256 invoiceId = _invoiceIdCounter;

        // Calculate amounts
        uint256 subtotal = 0;
        for (uint256 i = 0; i < items.length; i++) {
            require(items[i].quantity > 0, "InvoiceManager: invalid quantity");
            _invoiceItems[invoiceId].push(items[i]);
            subtotal += items[i].totalPrice;
        }

        uint256 discountAmount = (subtotal * discountRate) / 10000;
        uint256 taxableAmount = subtotal - discountAmount;
        uint256 taxAmount = (taxableAmount * taxRate) / 10000;
        uint256 totalAmount = taxableAmount + taxAmount;

        // Generate blockchain hash
        bytes32 invoiceHash = keccak256(
            abi.encodePacked(
                invoiceId,
                customerId,
                totalAmount,
                block.timestamp,
                msg.sender
            )
        );

        _invoices[invoiceId] = Invoice({
            id: invoiceId,
            orderId: orderId,
            customerId: customerId,
            customerName: customerName,
            items: new InvoiceItem[](0), // Stored separately
            subtotal: subtotal,
            taxRate: taxRate,
            taxAmount: taxAmount,
            discountRate: discountRate,
            discountAmount: discountAmount,
            totalAmount: totalAmount,
            status: InvoiceStatus.DRAFT,
            issueDate: block.timestamp,
            dueDate: dueDate,
            paidDate: 0,
            blockchainHash: _bytes32ToString(invoiceHash)
        });

        if (orderId != 0) {
            _orderToInvoice[orderId] = invoiceId;
        }

        _customerInvoices[customerId].push(invoiceId);
        _allInvoiceIds.push(invoiceId);

        // Update stats
        stats.totalInvoices++;
        stats.draftInvoices++;
        stats.totalValue += totalAmount;
        stats.pendingValue += totalAmount;

        emit InvoiceCreated(
            invoiceId,
            customerId,
            orderId,
            totalAmount,
            _invoices[invoiceId].blockchainHash
        );

        return invoiceId;
    }

    /**
     * @notice Send an invoice to customer
     * @param invoiceId The invoice ID
     */
    function sendInvoice(
        uint256 invoiceId
    ) external onlyManagerOrAbove whenNotPaused invoiceExists(invoiceId) {
        Invoice storage invoice = _invoices[invoiceId];
        require(
            invoice.status == InvoiceStatus.DRAFT,
            "InvoiceManager: invoice not in draft status"
        );

        invoice.status = InvoiceStatus.SENT;
        invoice.issueDate = block.timestamp;

        stats.draftInvoices--;
        stats.sentInvoices++;

        emit InvoiceSent(invoiceId, msg.sender, block.timestamp);
        emit InvoiceStatusUpdated(
            invoiceId,
            InvoiceStatus.DRAFT,
            InvoiceStatus.SENT,
            msg.sender
        );
    }

    /**
     * @notice Record payment for an invoice
     * @param invoiceId The invoice ID
     * @param amount Payment amount
     * @param paymentMethod Payment method (e.g., "Credit Card", "Wire Transfer", "Crypto")
     * @param transactionRef External transaction reference
     */
    function recordPayment(
        uint256 invoiceId,
        uint256 amount,
        string memory paymentMethod,
        string memory transactionRef
    ) external onlyManagerOrAbove whenNotPaused invoiceExists(invoiceId) {
        Invoice storage invoice = _invoices[invoiceId];

        require(
            invoice.status == InvoiceStatus.SENT ||
                invoice.status == InvoiceStatus.OVERDUE,
            "InvoiceManager: invoice not payable"
        );
        require(amount > 0, "InvoiceManager: payment amount must be positive");
        require(
            amount <= invoice.totalAmount,
            "InvoiceManager: payment exceeds invoice amount"
        );

        // Record payment
        _paymentHistory[invoiceId].push(
            PaymentRecord({
                invoiceId: invoiceId,
                amount: amount,
                paymentMethod: paymentMethod,
                transactionRef: transactionRef,
                timestamp: block.timestamp,
                recordedBy: msg.sender
            })
        );

        // Check if fully paid
        uint256 totalPaid = 0;
        for (uint256 i = 0; i < _paymentHistory[invoiceId].length; i++) {
            totalPaid += _paymentHistory[invoiceId][i].amount;
        }

        if (totalPaid >= invoice.totalAmount) {
            InvoiceStatus previousStatus = invoice.status;
            invoice.status = InvoiceStatus.PAID;
            invoice.paidDate = block.timestamp;

            // Update stats
            if (previousStatus == InvoiceStatus.SENT) stats.sentInvoices--;
            else if (previousStatus == InvoiceStatus.OVERDUE) {
                stats.overdueInvoices--;
                stats.overdueValue -= invoice.totalAmount;
            }
            stats.paidInvoices++;
            stats.paidValue += invoice.totalAmount;
            stats.pendingValue -= invoice.totalAmount;

            emit InvoicePaid(invoiceId, totalPaid, paymentMethod, msg.sender);
            emit InvoiceStatusUpdated(
                invoiceId,
                previousStatus,
                InvoiceStatus.PAID,
                msg.sender
            );
        }

        emit PaymentRecorded(invoiceId, amount, transactionRef);
    }

    /**
     * @notice Mark an invoice as overdue
     * @param invoiceId The invoice ID
     */
    function markOverdue(
        uint256 invoiceId
    ) external onlyManagerOrAbove invoiceExists(invoiceId) {
        Invoice storage invoice = _invoices[invoiceId];
        require(
            invoice.status == InvoiceStatus.SENT,
            "InvoiceManager: invoice not in sent status"
        );
        require(
            block.timestamp > invoice.dueDate,
            "InvoiceManager: invoice not yet due"
        );

        invoice.status = InvoiceStatus.OVERDUE;

        stats.sentInvoices--;
        stats.overdueInvoices++;
        stats.overdueValue += invoice.totalAmount;

        uint256 daysOverdue = (block.timestamp - invoice.dueDate) / 1 days;

        emit InvoiceOverdue(invoiceId, daysOverdue);
        emit InvoiceStatusUpdated(
            invoiceId,
            InvoiceStatus.SENT,
            InvoiceStatus.OVERDUE,
            msg.sender
        );
    }

    /**
     * @notice Cancel an invoice
     * @param invoiceId The invoice ID
     */
    function cancelInvoice(
        uint256 invoiceId
    ) external onlyManagerOrAbove whenNotPaused invoiceExists(invoiceId) {
        Invoice storage invoice = _invoices[invoiceId];
        require(
            invoice.status == InvoiceStatus.DRAFT ||
                invoice.status == InvoiceStatus.SENT,
            "InvoiceManager: invoice cannot be cancelled"
        );

        InvoiceStatus previousStatus = invoice.status;
        invoice.status = InvoiceStatus.CANCELLED;

        // Update stats
        if (previousStatus == InvoiceStatus.DRAFT) stats.draftInvoices--;
        else if (previousStatus == InvoiceStatus.SENT) stats.sentInvoices--;
        stats.cancelledInvoices++;
        stats.pendingValue -= invoice.totalAmount;

        emit InvoiceStatusUpdated(
            invoiceId,
            previousStatus,
            InvoiceStatus.CANCELLED,
            msg.sender
        );
    }

    /**
     * @notice Batch check overdue invoices
     */
    function checkOverdueInvoices() external onlyManagerOrAbove {
        for (uint256 i = 0; i < _allInvoiceIds.length; i++) {
            uint256 invoiceId = _allInvoiceIds[i];
            Invoice storage invoice = _invoices[invoiceId];

            if (
                invoice.status == InvoiceStatus.SENT &&
                block.timestamp > invoice.dueDate
            ) {
                invoice.status = InvoiceStatus.OVERDUE;
                stats.sentInvoices--;
                stats.overdueInvoices++;
                stats.overdueValue += invoice.totalAmount;

                uint256 daysOverdue = (block.timestamp - invoice.dueDate) /
                    1 days;
                emit InvoiceOverdue(invoiceId, daysOverdue);
            }
        }
    }

    // ============ View Functions ============

    /**
     * @notice Get invoice by ID
     * @param invoiceId The invoice ID
     * @return id Invoice ID
     * @return orderId Associated order ID
     * @return customerId Customer ID
     * @return customerName Customer name
     * @return subtotal Subtotal amount
     * @return taxAmount Tax amount
     * @return discountAmount Discount amount
     * @return totalAmount Total amount
     * @return status Invoice status
     * @return issueDate Issue date timestamp
     * @return dueDate Due date timestamp
     * @return paidDate Payment date timestamp
     * @return blockchainHash Blockchain verification hash
     */
    function getInvoice(
        uint256 invoiceId
    )
        external
        view
        invoiceExists(invoiceId)
        returns (
            uint256 id,
            uint256 orderId,
            uint256 customerId,
            string memory customerName,
            uint256 subtotal,
            uint256 taxAmount,
            uint256 discountAmount,
            uint256 totalAmount,
            InvoiceStatus status,
            uint256 issueDate,
            uint256 dueDate,
            uint256 paidDate,
            string memory blockchainHash
        )
    {
        Invoice storage invoice = _invoices[invoiceId];
        return (
            invoice.id,
            invoice.orderId,
            invoice.customerId,
            invoice.customerName,
            invoice.subtotal,
            invoice.taxAmount,
            invoice.discountAmount,
            invoice.totalAmount,
            invoice.status,
            invoice.issueDate,
            invoice.dueDate,
            invoice.paidDate,
            invoice.blockchainHash
        );
    }

    /**
     * @notice Get invoice items
     * @param invoiceId The invoice ID
     * @return InvoiceItem[] Array of items
     */
    function getInvoiceItems(
        uint256 invoiceId
    ) external view invoiceExists(invoiceId) returns (InvoiceItem[] memory) {
        return _invoiceItems[invoiceId];
    }

    /**
     * @notice Get payment history for an invoice
     * @param invoiceId The invoice ID
     * @return PaymentRecord[] Array of payment records
     */
    function getPaymentHistory(
        uint256 invoiceId
    ) external view invoiceExists(invoiceId) returns (PaymentRecord[] memory) {
        return _paymentHistory[invoiceId];
    }

    /**
     * @notice Get invoices by customer
     * @param customerId Customer ID
     * @return uint256[] Array of invoice IDs
     */
    function getCustomerInvoices(
        uint256 customerId
    ) external view returns (uint256[] memory) {
        return _customerInvoices[customerId];
    }

    /**
     * @notice Get invoice by order ID
     * @param orderId Order ID
     * @return uint256 Invoice ID
     */
    function getInvoiceByOrder(
        uint256 orderId
    ) external view returns (uint256) {
        return _orderToInvoice[orderId];
    }

    /**
     * @notice Get invoices by status
     * @param status Invoice status to filter
     * @return uint256[] Array of invoice IDs
     */
    function getInvoicesByStatus(
        InvoiceStatus status
    ) external view returns (uint256[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < _allInvoiceIds.length; i++) {
            if (_invoices[_allInvoiceIds[i]].status == status) {
                count++;
            }
        }

        uint256[] memory result = new uint256[](count);
        uint256 index = 0;
        for (uint256 i = 0; i < _allInvoiceIds.length; i++) {
            if (_invoices[_allInvoiceIds[i]].status == status) {
                result[index] = _allInvoiceIds[i];
                index++;
            }
        }

        return result;
    }

    /**
     * @notice Get all invoice IDs
     * @return uint256[] Array of all invoice IDs
     */
    function getAllInvoiceIds() external view returns (uint256[] memory) {
        return _allInvoiceIds;
    }

    /**
     * @notice Get invoice count
     * @return uint256 Total number of invoices
     */
    function getInvoiceCount() external view returns (uint256) {
        return _allInvoiceIds.length;
    }

    /**
     * @notice Get invoice statistics
     * @return InvoiceStats struct
     */
    function getInvoiceStats() external view returns (InvoiceStats memory) {
        return stats;
    }

    /**
     * @notice Get overdue invoices
     * @return uint256[] Array of overdue invoice IDs
     */
    function getOverdueInvoices() external view returns (uint256[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < _allInvoiceIds.length; i++) {
            Invoice storage invoice = _invoices[_allInvoiceIds[i]];
            if (
                invoice.status == InvoiceStatus.OVERDUE ||
                (invoice.status == InvoiceStatus.SENT &&
                    block.timestamp > invoice.dueDate)
            ) {
                count++;
            }
        }

        uint256[] memory result = new uint256[](count);
        uint256 index = 0;
        for (uint256 i = 0; i < _allInvoiceIds.length; i++) {
            Invoice storage invoice = _invoices[_allInvoiceIds[i]];
            if (
                invoice.status == InvoiceStatus.OVERDUE ||
                (invoice.status == InvoiceStatus.SENT &&
                    block.timestamp > invoice.dueDate)
            ) {
                result[index] = _allInvoiceIds[i];
                index++;
            }
        }

        return result;
    }

    // ============ Internal Functions ============

    function _bytes32ToString(
        bytes32 _bytes32
    ) internal pure returns (string memory) {
        bytes memory bytesArray = new bytes(66);
        bytesArray[0] = "0";
        bytesArray[1] = "x";
        for (uint256 i = 0; i < 32; i++) {
            bytesArray[2 + i * 2] = _toHexChar(uint8(_bytes32[i] >> 4));
            bytesArray[3 + i * 2] = _toHexChar(uint8(_bytes32[i] & 0x0f));
        }
        return string(bytesArray);
    }

    function _toHexChar(uint8 _value) internal pure returns (bytes1) {
        if (_value < 10) {
            return bytes1(_value + 48);
        } else {
            return bytes1(_value + 87);
        }
    }
}

contracts/OrderManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "./interfaces/IBlockERP.sol";
import "./BlockERPCore.sol";

/**
 * @title OrderManager
 * @author BlockERP Team
 * @notice Manages orders with full lifecycle tracking and blockchain verification
 * @dev Integrates with BlockERPCore for access control
 */
contract OrderManager is IOrderTypes {
    // ============ State Variables ============

    /// @notice Reference to core contract
    BlockERPCore public immutable core;

    /// @notice Order counter for unique IDs
    uint256 private _orderIdCounter;

    /// @notice Mapping of order ID to Order data
    mapping(uint256 => Order) private _orders;

    /// @notice Mapping of order ID to items (separate storage for array)
    mapping(uint256 => OrderItem[]) private _orderItems;

    /// @notice Mapping of customer ID to their order IDs
    mapping(uint256 => uint256[]) private _customerOrders;

    /// @notice Array of all order IDs
    uint256[] private _allOrderIds;

    /// @notice Mapping of blockchain hash to order ID
    mapping(bytes32 => uint256) private _hashToOrder;

    /// @notice Order statistics
    struct OrderStats {
        uint256 totalOrders;
        uint256 pendingOrders;
        uint256 processingOrders;
        uint256 shippedOrders;
        uint256 deliveredOrders;
        uint256 cancelledOrders;
        uint256 totalRevenue;
    }

    OrderStats public stats;

    // ============ Events ============

    event OrderCreated(
        uint256 indexed orderId,
        uint256 indexed customerId,
        uint256 totalAmount,
        string blockchainHash
    );

    event OrderStatusUpdated(
        uint256 indexed orderId,
        OrderStatus previousStatus,
        OrderStatus newStatus,
        address indexed updatedBy
    );

    event OrderVerified(
        uint256 indexed orderId,
        bytes32 verificationHash,
        address indexed verifiedBy
    );

    event OrderCancelled(
        uint256 indexed orderId,
        string reason,
        address indexed cancelledBy
    );

    event OrderItemAdded(
        uint256 indexed orderId,
        uint256 indexed productId,
        uint256 quantity
    );

    // ============ Modifiers ============

    modifier onlyAdmin() {
        require(
            core.hasRole(msg.sender, IAccessControl.Role.ADMIN),
            "OrderManager: caller is not admin"
        );
        _;
    }

    modifier onlyManagerOrAbove() {
        require(
            core.hasRole(msg.sender, IAccessControl.Role.MANAGER),
            "OrderManager: insufficient permissions"
        );
        _;
    }

    modifier whenNotPaused() {
        require(!core.paused(), "OrderManager: system is paused");
        _;
    }

    modifier orderExists(uint256 orderId) {
        require(_orders[orderId].id != 0, "OrderManager: order does not exist");
        _;
    }

    // ============ Constructor ============

    constructor(address _coreAddress) {
        require(
            _coreAddress != address(0),
            "OrderManager: invalid core address"
        );
        core = BlockERPCore(_coreAddress);
        _orderIdCounter = 1000; // Start from 1000 for readability
    }

    // ============ Order Management Functions ============

    /**
     * @notice Create a new order
     * @param customerId Customer identifier
     * @param customerName Customer name for display
     * @param items Array of order items
     * @return orderId The ID of the created order
     */
    function createOrder(
        uint256 customerId,
        string memory customerName,
        OrderItem[] memory items
    ) external onlyManagerOrAbove whenNotPaused returns (uint256) {
        require(items.length > 0, "OrderManager: order must have items");
        require(
            bytes(customerName).length > 0,
            "OrderManager: customer name required"
        );

        _orderIdCounter++;
        uint256 orderId = _orderIdCounter;

        uint256 totalAmount = 0;
        for (uint256 i = 0; i < items.length; i++) {
            require(items[i].quantity > 0, "OrderManager: invalid quantity");
            _orderItems[orderId].push(items[i]);
            totalAmount += items[i].totalPrice;
            emit OrderItemAdded(orderId, items[i].productId, items[i].quantity);
        }

        // Generate blockchain hash
        bytes32 orderHash = keccak256(
            abi.encodePacked(
                orderId,
                customerId,
                totalAmount,
                block.timestamp,
                msg.sender
            )
        );

        string memory hashString = _bytes32ToString(orderHash);

        _orders[orderId] = Order({
            id: orderId,
            customerId: customerId,
            customerName: customerName,
            items: new OrderItem[](0), // Items stored separately
            totalAmount: totalAmount,
            status: OrderStatus.PENDING,
            createdAt: block.timestamp,
            updatedAt: block.timestamp,
            blockchainHash: hashString,
            verified: false
        });

        _customerOrders[customerId].push(orderId);
        _allOrderIds.push(orderId);
        _hashToOrder[orderHash] = orderId;

        // Update stats
        stats.totalOrders++;
        stats.pendingOrders++;
        stats.totalRevenue += totalAmount;

        emit OrderCreated(orderId, customerId, totalAmount, hashString);

        return orderId;
    }

    /**
     * @notice Update order status
     * @param orderId The order ID
     * @param newStatus The new status
     */
    function updateOrderStatus(
        uint256 orderId,
        OrderStatus newStatus
    ) external onlyManagerOrAbove whenNotPaused orderExists(orderId) {
        Order storage order = _orders[orderId];
        OrderStatus previousStatus = order.status;

        require(previousStatus != newStatus, "OrderManager: status unchanged");
        require(
            previousStatus != OrderStatus.CANCELLED &&
                previousStatus != OrderStatus.REFUNDED,
            "OrderManager: cannot update cancelled/refunded order"
        );

        // Validate status transitions
        _validateStatusTransition(previousStatus, newStatus);

        // Update counters
        _updateStatusCounters(previousStatus, newStatus);

        order.status = newStatus;
        order.updatedAt = block.timestamp;

        emit OrderStatusUpdated(orderId, previousStatus, newStatus, msg.sender);
    }

    /**
     * @notice Cancel an order
     * @param orderId The order ID
     * @param reason Cancellation reason
     */
    function cancelOrder(
        uint256 orderId,
        string memory reason
    ) external onlyManagerOrAbove whenNotPaused orderExists(orderId) {
        Order storage order = _orders[orderId];

        require(
            order.status == OrderStatus.PENDING ||
                order.status == OrderStatus.PROCESSING,
            "OrderManager: order cannot be cancelled"
        );

        OrderStatus previousStatus = order.status;
        _updateStatusCounters(previousStatus, OrderStatus.CANCELLED);

        order.status = OrderStatus.CANCELLED;
        order.updatedAt = block.timestamp;

        emit OrderCancelled(orderId, reason, msg.sender);
        emit OrderStatusUpdated(
            orderId,
            previousStatus,
            OrderStatus.CANCELLED,
            msg.sender
        );
    }

    /**
     * @notice Verify an order on blockchain
     * @param orderId The order ID
     */
    function verifyOrder(
        uint256 orderId
    ) external onlyAdmin orderExists(orderId) {
        Order storage order = _orders[orderId];
        require(!order.verified, "OrderManager: order already verified");

        bytes32 verificationHash = keccak256(
            abi.encodePacked(
                order.id,
                order.customerId,
                order.totalAmount,
                order.createdAt,
                block.timestamp,
                msg.sender
            )
        );

        order.verified = true;
        order.updatedAt = block.timestamp;

        emit OrderVerified(orderId, verificationHash, msg.sender);
    }

    /**
     * @notice Batch verify multiple orders
     * @param orderIds Array of order IDs to verify
     */
    function batchVerifyOrders(uint256[] memory orderIds) external onlyAdmin {
        for (uint256 i = 0; i < orderIds.length; i++) {
            if (
                _orders[orderIds[i]].id != 0 && !_orders[orderIds[i]].verified
            ) {
                _orders[orderIds[i]].verified = true;
                _orders[orderIds[i]].updatedAt = block.timestamp;

                bytes32 verificationHash = keccak256(
                    abi.encodePacked(orderIds[i], block.timestamp, msg.sender)
                );

                emit OrderVerified(orderIds[i], verificationHash, msg.sender);
            }
        }
    }

    // ============ View Functions ============

    /**
     * @notice Get order by ID
     * @param orderId The order ID
     * @return id Order ID
     * @return customerId Customer ID
     * @return customerName Customer name
     * @return totalAmount Total order amount
     * @return status Order status
     * @return createdAt Creation timestamp
     * @return updatedAt Last update timestamp
     * @return blockchainHash Blockchain verification hash
     * @return verified Whether order is verified
     */
    function getOrder(
        uint256 orderId
    )
        external
        view
        orderExists(orderId)
        returns (
            uint256 id,
            uint256 customerId,
            string memory customerName,
            uint256 totalAmount,
            OrderStatus status,
            uint256 createdAt,
            uint256 updatedAt,
            string memory blockchainHash,
            bool verified
        )
    {
        Order storage order = _orders[orderId];
        return (
            order.id,
            order.customerId,
            order.customerName,
            order.totalAmount,
            order.status,
            order.createdAt,
            order.updatedAt,
            order.blockchainHash,
            order.verified
        );
    }

    /**
     * @notice Get order items
     * @param orderId The order ID
     * @return OrderItem[] Array of items
     */
    function getOrderItems(
        uint256 orderId
    ) external view orderExists(orderId) returns (OrderItem[] memory) {
        return _orderItems[orderId];
    }

    /**
     * @notice Get orders by customer
     * @param customerId Customer ID
     * @return uint256[] Array of order IDs
     */
    function getCustomerOrders(
        uint256 customerId
    ) external view returns (uint256[] memory) {
        return _customerOrders[customerId];
    }

    /**
     * @notice Get orders by status
     * @param status Order status to filter
     * @return uint256[] Array of order IDs
     */
    function getOrdersByStatus(
        OrderStatus status
    ) external view returns (uint256[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < _allOrderIds.length; i++) {
            if (_orders[_allOrderIds[i]].status == status) {
                count++;
            }
        }

        uint256[] memory result = new uint256[](count);
        uint256 index = 0;
        for (uint256 i = 0; i < _allOrderIds.length; i++) {
            if (_orders[_allOrderIds[i]].status == status) {
                result[index] = _allOrderIds[i];
                index++;
            }
        }

        return result;
    }

    /**
     * @notice Get all order IDs
     * @return uint256[] Array of all order IDs
     */
    function getAllOrderIds() external view returns (uint256[] memory) {
        return _allOrderIds;
    }

    /**
     * @notice Get order count
     * @return uint256 Total number of orders
     */
    function getOrderCount() external view returns (uint256) {
        return _allOrderIds.length;
    }

    /**
     * @notice Get order statistics
     * @return OrderStats struct
     */
    function getOrderStats() external view returns (OrderStats memory) {
        return stats;
    }

    /**
     * @notice Verify order hash
     * @param orderId Order ID
     * @param providedHash Hash to verify
     * @return bool True if hash matches
     */
    function verifyOrderHash(
        uint256 orderId,
        bytes32 providedHash
    ) external view orderExists(orderId) returns (bool) {
        bytes32 storedHash = keccak256(
            abi.encodePacked(_orders[orderId].blockchainHash)
        );
        return storedHash == providedHash;
    }

    /**
     * @notice Get recent orders
     * @param count Number of orders to return
     * @return uint256[] Array of recent order IDs
     */
    function getRecentOrders(
        uint256 count
    ) external view returns (uint256[] memory) {
        uint256 total = _allOrderIds.length;
        uint256 resultCount = count > total ? total : count;
        uint256[] memory result = new uint256[](resultCount);

        for (uint256 i = 0; i < resultCount; i++) {
            result[i] = _allOrderIds[total - 1 - i];
        }

        return result;
    }

    // ============ Internal Functions ============

    function _validateStatusTransition(
        OrderStatus from,
        OrderStatus to
    ) internal pure {
        if (from == OrderStatus.PENDING) {
            require(
                to == OrderStatus.PROCESSING || to == OrderStatus.CANCELLED,
                "OrderManager: invalid status transition from PENDING"
            );
        } else if (from == OrderStatus.PROCESSING) {
            require(
                to == OrderStatus.SHIPPED || to == OrderStatus.CANCELLED,
                "OrderManager: invalid status transition from PROCESSING"
            );
        } else if (from == OrderStatus.SHIPPED) {
            require(
                to == OrderStatus.DELIVERED || to == OrderStatus.REFUNDED,
                "OrderManager: invalid status transition from SHIPPED"
            );
        } else if (from == OrderStatus.DELIVERED) {
            require(
                to == OrderStatus.REFUNDED,
                "OrderManager: invalid status transition from DELIVERED"
            );
        }
    }

    function _updateStatusCounters(OrderStatus from, OrderStatus to) internal {
        // Decrement old status counter
        if (from == OrderStatus.PENDING) stats.pendingOrders--;
        else if (from == OrderStatus.PROCESSING) stats.processingOrders--;
        else if (from == OrderStatus.SHIPPED) stats.shippedOrders--;
        else if (from == OrderStatus.DELIVERED) stats.deliveredOrders--;

        // Increment new status counter
        if (to == OrderStatus.PENDING) stats.pendingOrders++;
        else if (to == OrderStatus.PROCESSING) stats.processingOrders++;
        else if (to == OrderStatus.SHIPPED) stats.shippedOrders++;
        else if (to == OrderStatus.DELIVERED) stats.deliveredOrders++;
        else if (to == OrderStatus.CANCELLED) stats.cancelledOrders++;
    }

    function _bytes32ToString(
        bytes32 _bytes32
    ) internal pure returns (string memory) {
        bytes memory bytesArray = new bytes(66);
        bytesArray[0] = "0";
        bytesArray[1] = "x";
        for (uint256 i = 0; i < 32; i++) {
            bytesArray[2 + i * 2] = _toHexChar(uint8(_bytes32[i] >> 4));
            bytesArray[3 + i * 2] = _toHexChar(uint8(_bytes32[i] & 0x0f));
        }
        return string(bytesArray);
    }

    function _toHexChar(uint8 _value) internal pure returns (bytes1) {
        if (_value < 10) {
            return bytes1(_value + 48);
        } else {
            return bytes1(_value + 87);
        }
    }
}

contracts/SupplyChain.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "./interfaces/IBlockERP.sol";
import "./BlockERPCore.sol";

/**
 * @title SupplyChain
 * @author BlockERP Team
 * @notice Supply chain tracking with full provenance and verification
 * @dev Provides immutable supply chain records with hash-linked events
 */
contract SupplyChain is ISupplyChainTypes {
    // ============ State Variables ============

    /// @notice Reference to core contract
    BlockERPCore public immutable core;

    /// @notice Tracking record counter
    uint256 private _recordIdCounter;

    /// @notice Mapping of product ID to supply chain record
    mapping(uint256 => SupplyChainRecord) private _records;

    /// @notice Mapping of product ID to tracking events
    mapping(uint256 => TrackingEvent[]) private _trackingEvents;

    /// @notice Mapping of product ID to current status
    mapping(uint256 => TrackingStatus) private _currentStatus;

    /// @notice Mapping of hash to product ID for verification
    mapping(bytes32 => uint256) private _hashToProduct;

    /// @notice Array of all tracked product IDs
    uint256[] private _trackedProducts;

    /// @notice Registered handlers/stakeholders
    mapping(address => HandlerInfo) public handlers;
    address[] private _handlerAddresses;

    struct HandlerInfo {
        string name;
        string handlerType; // Manufacturer, Warehouse, Distributor, Retailer
        string location;
        bool isActive;
        uint256 registeredAt;
    }

    /// @notice Supply chain statistics
    struct SupplyChainStats {
        uint256 totalTrackedProducts;
        uint256 activeShipments;
        uint256 completedShipments;
        uint256 totalEvents;
        uint256 registeredHandlers;
    }

    SupplyChainStats public stats;

    // ============ Events ============

    event TrackingStarted(
        uint256 indexed productId,
        string origin,
        string destination,
        bytes32 initialHash
    );

    event TrackingEventRecorded(
        uint256 indexed productId,
        TrackingStatus status,
        string location,
        string handler,
        bytes32 eventHash
    );

    event TrackingCompleted(
        uint256 indexed productId,
        uint256 totalEvents,
        bytes32 finalHash
    );

    event HandlerRegistered(
        address indexed handlerAddress,
        string name,
        string handlerType
    );

    event HandlerDeactivated(
        address indexed handlerAddress,
        address indexed deactivatedBy
    );

    event ProvenanceVerified(
        uint256 indexed productId,
        bool isValid,
        address verifiedBy
    );

    // ============ Modifiers ============

    modifier onlyAdmin() {
        require(
            core.hasRole(msg.sender, IAccessControl.Role.ADMIN),
            "SupplyChain: caller is not admin"
        );
        _;
    }

    modifier onlyManagerOrAbove() {
        require(
            core.hasRole(msg.sender, IAccessControl.Role.MANAGER),
            "SupplyChain: insufficient permissions"
        );
        _;
    }

    modifier onlyActiveHandler() {
        require(
            handlers[msg.sender].isActive,
            "SupplyChain: not an active handler"
        );
        _;
    }

    modifier productTracked(uint256 productId) {
        require(
            _records[productId].productId != 0,
            "SupplyChain: product not tracked"
        );
        _;
    }

    modifier trackingActive(uint256 productId) {
        require(
            !_records[productId].isComplete,
            "SupplyChain: tracking already completed"
        );
        _;
    }

    // ============ Constructor ============

    constructor(address _coreAddress) {
        require(
            _coreAddress != address(0),
            "SupplyChain: invalid core address"
        );
        core = BlockERPCore(_coreAddress);
        _recordIdCounter = 0;
    }

    // ============ Handler Management ============

    /**
     * @notice Register a new handler/stakeholder
     * @param handlerAddress Handler's blockchain address
     * @param name Handler name
     * @param handlerType Type (Manufacturer, Warehouse, Distributor, Retailer)
     * @param location Handler location
     */
    function registerHandler(
        address handlerAddress,
        string memory name,
        string memory handlerType,
        string memory location
    ) external onlyAdmin {
        require(handlerAddress != address(0), "SupplyChain: invalid address");
        require(
            !handlers[handlerAddress].isActive,
            "SupplyChain: handler already exists"
        );
        require(bytes(name).length > 0, "SupplyChain: name required");

        handlers[handlerAddress] = HandlerInfo({
            name: name,
            handlerType: handlerType,
            location: location,
            isActive: true,
            registeredAt: block.timestamp
        });

        _handlerAddresses.push(handlerAddress);
        stats.registeredHandlers++;

        emit HandlerRegistered(handlerAddress, name, handlerType);
    }

    /**
     * @notice Deactivate a handler
     * @param handlerAddress Handler address to deactivate
     */
    function deactivateHandler(address handlerAddress) external onlyAdmin {
        require(
            handlers[handlerAddress].isActive,
            "SupplyChain: handler not active"
        );

        handlers[handlerAddress].isActive = false;
        stats.registeredHandlers--;

        emit HandlerDeactivated(handlerAddress, msg.sender);
    }

    /**
     * @notice Self-register as a handler (requires admin approval)
     * @param name Handler name
     * @param handlerType Type of handler
     * @param location Location
     */
    function selfRegisterHandler(
        string memory name,
        string memory handlerType,
        string memory location
    ) external {
        require(
            !handlers[msg.sender].isActive,
            "SupplyChain: already registered"
        );
        require(bytes(name).length > 0, "SupplyChain: name required");

        // Register but inactive until admin approves
        handlers[msg.sender] = HandlerInfo({
            name: name,
            handlerType: handlerType,
            location: location,
            isActive: false,
            registeredAt: block.timestamp
        });

        _handlerAddresses.push(msg.sender);
    }

    /**
     * @notice Approve a pending handler registration
     * @param handlerAddress Handler to approve
     */
    function approveHandler(address handlerAddress) external onlyAdmin {
        require(
            handlers[handlerAddress].registeredAt != 0,
            "SupplyChain: handler not found"
        );
        require(
            !handlers[handlerAddress].isActive,
            "SupplyChain: already active"
        );

        handlers[handlerAddress].isActive = true;
        stats.registeredHandlers++;

        emit HandlerRegistered(
            handlerAddress,
            handlers[handlerAddress].name,
            handlers[handlerAddress].handlerType
        );
    }

    // ============ Tracking Functions ============

    /**
     * @notice Start tracking a product
     * @param productId Product ID to track
     * @param origin Origin location/manufacturer
     * @param destination Final destination
     * @return success True if tracking started
     */
    function startTracking(
        uint256 productId,
        string memory origin,
        string memory destination
    ) external onlyManagerOrAbove returns (bool) {
        require(productId != 0, "SupplyChain: invalid product ID");
        require(
            _records[productId].productId == 0,
            "SupplyChain: already tracked"
        );
        require(bytes(origin).length > 0, "SupplyChain: origin required");
        require(
            bytes(destination).length > 0,
            "SupplyChain: destination required"
        );

        bytes32 initialHash = keccak256(
            abi.encodePacked(
                productId,
                origin,
                destination,
                block.timestamp,
                msg.sender
            )
        );

        _records[productId] = SupplyChainRecord({
            productId: productId,
            origin: origin,
            destination: destination,
            events: new TrackingEvent[](0), // Events stored separately
            createdAt: block.timestamp,
            isComplete: false
        });

        // Record initial event
        _trackingEvents[productId].push(
            TrackingEvent({
                productId: productId,
                status: TrackingStatus.MANUFACTURED,
                location: origin,
                handler: handlers[msg.sender].isActive
                    ? handlers[msg.sender].name
                    : "System",
                notes: "Tracking initiated",
                timestamp: block.timestamp,
                previousHash: bytes32(0),
                currentHash: initialHash
            })
        );

        _currentStatus[productId] = TrackingStatus.MANUFACTURED;
        _trackedProducts.push(productId);
        _hashToProduct[initialHash] = productId;

        stats.totalTrackedProducts++;
        stats.activeShipments++;
        stats.totalEvents++;

        emit TrackingStarted(productId, origin, destination, initialHash);
        emit TrackingEventRecorded(
            productId,
            TrackingStatus.MANUFACTURED,
            origin,
            "System",
            initialHash
        );

        return true;
    }

    /**
     * @notice Record a tracking event
     * @param productId Product ID
     * @param status New status
     * @param location Current location
     * @param notes Additional notes
     */
    function recordEvent(
        uint256 productId,
        TrackingStatus status,
        string memory location,
        string memory notes
    ) external productTracked(productId) trackingActive(productId) {
        // Must be admin/manager OR active handler
        require(
            core.hasRole(msg.sender, IAccessControl.Role.MANAGER) ||
                handlers[msg.sender].isActive,
            "SupplyChain: not authorized"
        );

        TrackingEvent[] storage events = _trackingEvents[productId];
        bytes32 previousHash = events.length > 0
            ? events[events.length - 1].currentHash
            : bytes32(0);

        bytes32 currentHash = keccak256(
            abi.encodePacked(
                productId,
                status,
                location,
                block.timestamp,
                previousHash,
                msg.sender
            )
        );

        string memory handlerName = handlers[msg.sender].isActive
            ? handlers[msg.sender].name
            : "System";

        events.push(
            TrackingEvent({
                productId: productId,
                status: status,
                location: location,
                handler: handlerName,
                notes: notes,
                timestamp: block.timestamp,
                previousHash: previousHash,
                currentHash: currentHash
            })
        );

        _currentStatus[productId] = status;
        _hashToProduct[currentHash] = productId;
        stats.totalEvents++;

        emit TrackingEventRecorded(
            productId,
            status,
            location,
            handlerName,
            currentHash
        );

        // Auto-complete if delivered or returned
        if (
            status == TrackingStatus.DELIVERED ||
            status == TrackingStatus.RETURNED
        ) {
            _completeTracking(productId);
        }
    }

    /**
     * @notice Record transit event
     * @param productId Product ID
     * @param fromLocation Origin location
     * @param toLocation Destination location
     * @param notes Notes
     */
    function recordTransit(
        uint256 productId,
        string memory fromLocation,
        string memory toLocation,
        string memory notes
    ) external productTracked(productId) trackingActive(productId) {
        require(
            core.hasRole(msg.sender, IAccessControl.Role.MANAGER) ||
                handlers[msg.sender].isActive,
            "SupplyChain: not authorized"
        );

        string memory transitNotes = string(
            abi.encodePacked(
                "Transit from ",
                fromLocation,
                " to ",
                toLocation,
                ". ",
                notes
            )
        );

        TrackingEvent[] storage events = _trackingEvents[productId];
        bytes32 previousHash = events.length > 0
            ? events[events.length - 1].currentHash
            : bytes32(0);

        bytes32 currentHash = keccak256(
            abi.encodePacked(
                productId,
                TrackingStatus.IN_TRANSIT,
                toLocation,
                block.timestamp,
                previousHash
            )
        );

        string memory handlerName = handlers[msg.sender].isActive
            ? handlers[msg.sender].name
            : "System";

        events.push(
            TrackingEvent({
                productId: productId,
                status: TrackingStatus.IN_TRANSIT,
                location: toLocation,
                handler: handlerName,
                notes: transitNotes,
                timestamp: block.timestamp,
                previousHash: previousHash,
                currentHash: currentHash
            })
        );

        _currentStatus[productId] = TrackingStatus.IN_TRANSIT;
        _hashToProduct[currentHash] = productId;
        stats.totalEvents++;

        emit TrackingEventRecorded(
            productId,
            TrackingStatus.IN_TRANSIT,
            toLocation,
            handlerName,
            currentHash
        );
    }

    /**
     * @notice Record quality check
     * @param productId Product ID
     * @param location Check location
     * @param passed Whether quality check passed
     * @param details Check details
     */
    function recordQualityCheck(
        uint256 productId,
        string memory location,
        bool passed,
        string memory details
    )
        external
        productTracked(productId)
        trackingActive(productId)
        onlyManagerOrAbove
    {
        string memory notes = passed
            ? string(abi.encodePacked("Quality check PASSED. ", details))
            : string(abi.encodePacked("Quality check FAILED. ", details));

        TrackingEvent[] storage events = _trackingEvents[productId];
        bytes32 previousHash = events.length > 0
            ? events[events.length - 1].currentHash
            : bytes32(0);

        bytes32 currentHash = keccak256(
            abi.encodePacked(
                productId,
                TrackingStatus.QUALITY_CHECK,
                passed,
                block.timestamp,
                previousHash
            )
        );

        events.push(
            TrackingEvent({
                productId: productId,
                status: TrackingStatus.QUALITY_CHECK,
                location: location,
                handler: handlers[msg.sender].isActive
                    ? handlers[msg.sender].name
                    : "Inspector",
                notes: notes,
                timestamp: block.timestamp,
                previousHash: previousHash,
                currentHash: currentHash
            })
        );

        _currentStatus[productId] = TrackingStatus.QUALITY_CHECK;
        _hashToProduct[currentHash] = productId;
        stats.totalEvents++;

        emit TrackingEventRecorded(
            productId,
            TrackingStatus.QUALITY_CHECK,
            location,
            "Inspector",
            currentHash
        );
    }

    /**
     * @notice Complete tracking manually
     * @param productId Product ID
     */
    function completeTracking(
        uint256 productId
    )
        external
        onlyManagerOrAbove
        productTracked(productId)
        trackingActive(productId)
    {
        _completeTracking(productId);
    }

    // ============ Verification Functions ============

    /**
     * @notice Verify complete provenance chain
     * @param productId Product ID
     * @return isValid True if chain is valid
     * @return eventCount Number of events in chain
     */
    function verifyProvenance(
        uint256 productId
    )
        external
        view
        productTracked(productId)
        returns (bool isValid, uint256 eventCount)
    {
        TrackingEvent[] storage events = _trackingEvents[productId];
        eventCount = events.length;

        if (eventCount == 0) return (false, 0);

        // Verify first event has no previous hash
        if (events[0].previousHash != bytes32(0)) return (false, eventCount);

        // Verify hash chain
        for (uint256 i = 1; i < eventCount; i++) {
            if (events[i].previousHash != events[i - 1].currentHash) {
                return (false, eventCount);
            }
        }

        return (true, eventCount);
    }

    /**
     * @notice Verify a specific event hash
     * @param productId Product ID
     * @param eventIndex Event index
     * @param providedHash Hash to verify
     * @return bool True if valid
     */
    function verifyEventHash(
        uint256 productId,
        uint256 eventIndex,
        bytes32 providedHash
    ) external view productTracked(productId) returns (bool) {
        require(
            eventIndex < _trackingEvents[productId].length,
            "SupplyChain: invalid event index"
        );
        return
            _trackingEvents[productId][eventIndex].currentHash == providedHash;
    }

    /**
     * @notice Get product ID by hash
     * @param hash Event hash
     * @return productId Product ID (0 if not found)
     */
    function getProductByHash(bytes32 hash) external view returns (uint256) {
        return _hashToProduct[hash];
    }

    // ============ View Functions ============

    /**
     * @notice Get tracking record
     * @param productId Product ID
     * @return origin Origin location
     * @return destination Destination
     * @return createdAt Creation timestamp
     * @return isComplete Completion status
     * @return eventCount Number of events
     */
    function getTrackingRecord(
        uint256 productId
    )
        external
        view
        productTracked(productId)
        returns (
            string memory origin,
            string memory destination,
            uint256 createdAt,
            bool isComplete,
            uint256 eventCount
        )
    {
        SupplyChainRecord storage record = _records[productId];
        return (
            record.origin,
            record.destination,
            record.createdAt,
            record.isComplete,
            _trackingEvents[productId].length
        );
    }

    /**
     * @notice Get all tracking events for a product
     * @param productId Product ID
     * @return TrackingEvent[] Array of events
     */
    function getTrackingEvents(
        uint256 productId
    ) external view productTracked(productId) returns (TrackingEvent[] memory) {
        return _trackingEvents[productId];
    }

    /**
     * @notice Get current status of a product
     * @param productId Product ID
     * @return TrackingStatus Current status
     */
    function getCurrentStatus(
        uint256 productId
    ) external view productTracked(productId) returns (TrackingStatus) {
        return _currentStatus[productId];
    }

    /**
     * @notice Get latest tracking event
     * @param productId Product ID
     * @return TrackingEvent Latest event
     */
    function getLatestEvent(
        uint256 productId
    ) external view productTracked(productId) returns (TrackingEvent memory) {
        TrackingEvent[] storage events = _trackingEvents[productId];
        require(events.length > 0, "SupplyChain: no events");
        return events[events.length - 1];
    }

    /**
     * @notice Get all tracked product IDs
     * @return uint256[] Array of product IDs
     */
    function getAllTrackedProducts() external view returns (uint256[] memory) {
        return _trackedProducts;
    }

    /**
     * @notice Get active shipments
     * @return uint256[] Array of product IDs with active tracking
     */
    function getActiveShipments() external view returns (uint256[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < _trackedProducts.length; i++) {
            if (!_records[_trackedProducts[i]].isComplete) {
                count++;
            }
        }

        uint256[] memory result = new uint256[](count);
        uint256 index = 0;
        for (uint256 i = 0; i < _trackedProducts.length; i++) {
            if (!_records[_trackedProducts[i]].isComplete) {
                result[index] = _trackedProducts[i];
                index++;
            }
        }

        return result;
    }

    /**
     * @notice Get all registered handlers
     * @return address[] Array of handler addresses
     */
    function getAllHandlers() external view returns (address[] memory) {
        return _handlerAddresses;
    }

    /**
     * @notice Get handler info
     * @param handlerAddress Handler address
     * @return HandlerInfo Handler information
     */
    function getHandlerInfo(
        address handlerAddress
    ) external view returns (HandlerInfo memory) {
        return handlers[handlerAddress];
    }

    /**
     * @notice Get supply chain statistics
     * @return SupplyChainStats Statistics struct
     */
    function getSupplyChainStats()
        external
        view
        returns (SupplyChainStats memory)
    {
        return stats;
    }

    /**
     * @notice Check if product is being tracked
     * @param productId Product ID
     * @return bool True if tracked
     */
    function isTracked(uint256 productId) external view returns (bool) {
        return _records[productId].productId != 0;
    }

    // ============ Internal Functions ============

    function _completeTracking(uint256 productId) internal {
        _records[productId].isComplete = true;

        TrackingEvent[] storage events = _trackingEvents[productId];
        bytes32 finalHash = events.length > 0
            ? events[events.length - 1].currentHash
            : bytes32(0);

        stats.activeShipments--;
        stats.completedShipments++;

        emit TrackingCompleted(productId, events.length, finalHash);
    }
}

